class Solution:
    def canChange(self, start: str, target: str) -> bool:
        start = list(start)
        target = list(target)
        for i in range(len(start)):
            if start[i] != target[i]:
                if start[i] == 'L' and target[i] != '_' and target[i] != 'L' and i > 0 and target[i-1] != '_':
                    return False
                if start[i] == 'R' and target[i] != '_' and target[i] != 'R' and i < len(target) - 1 and target[i+1] != '_':
                    return False
                if start[i] == '_' and target[i] != '_':
                    return False
        return True
```

